                url:  '/Notification/GetPendingCount',
                type: 'GET',
                success: function (res) {
                    var count  = res.count || 0;
                    var badge  = document.getElementById('sidebar-opd-badge');
                    if (!badge) return;
                    if (count > 0) {
                        badge.textContent = count > 99 ? '99+' : count;
